// dto/create-profile.dto.ts
export class CreateProfileDto {
 @IsString()
 @Length(2, 100)
 @Transform(({ value }) => sanitizeHtml(value))
 name: string;

 @IsEnum(ProfileCategory)
 category: ProfileCategory;

 @IsOptional()
 @IsString()
 @MaxLength(2000)
 description?: string;
}

